#include <stddef.h>
#include <stdlib.h>
#include <stdbool.h>
#include <pthread.h>

// Ring buffer bounded thread-safe con supporto shutdown
// Invarianti:
// - head indica il prossimo elemento da leggere (se count > 0)
// - tail indica la posizione dove scrivere il prossimo elemento
// - count == (tail - head) mod capacity, sempre 0 <= count <= capacity
// - Quando count == 0, il buffer è vuoto; quando count == capacity, è pieno
// - Tutte le operazioni sono protette dal mutex; le condition variable segnalano
//   cambiamenti di stato (non vuoto, non pieno, shutdown)

typedef struct {
    int*       data;          // array di elementi
    size_t     capacity;      // capacità massima
    size_t     head;          // indice di lettura
    size_t     tail;          // indice di scrittura
    size_t     count;         // numero di elementi presenti
    bool       shutdown;      // flag di terminazione
    pthread_mutex_t  mutex;
    pthread_cond_t   cond_push;  // segnalato quando buffer non è pieno
    pthread_cond_t   cond_pop;   // segnalato quando buffer non è vuoto
} ring_buffer_t;

// Crea un ring buffer con capacità specificata.
// Restituisce NULL in caso di errore di allocazione.
ring_buffer_t* ring_buffer_create(size_t capacity) {
    ring_buffer_t* rb = malloc(sizeof(ring_buffer_t));
    if (!rb) return NULL;

    rb->data = malloc(sizeof(int) * capacity);
    if (!rb->data) {
        free(rb);
        return NULL;
    }

    rb->capacity = capacity;
    rb->head = 0;
    rb->tail = 0;
    rb->count = 0;
    rb->shutdown = false;

    pthread_mutex_init(&rb->mutex, NULL);
    pthread_cond_init(&rb->cond_push, NULL);
    pthread_cond_init(&rb->cond_pop, NULL);

    return rb;
}

// Distrugge il ring buffer, liberando le risorse.
// Presuppone che nessun thread sia in attesa sulle condition variable.
void ring_buffer_destroy(ring_buffer_t* rb) {
    if (!rb) return;

    pthread_mutex_destroy(&rb->mutex);
    pthread_cond_destroy(&rb->cond_push);
    pthread_cond_destroy(&rb->cond_pop);
    free(rb->data);
    free(rb);
}

// Inserisce un elemento nel buffer.
// Restituisce true se successo, false se buffer in shutdown o errore.
// Se il buffer è pieno, il thread attende finché non c'è spazio o shutdown.
bool ring_buffer_push(ring_buffer_t* rb, int value) {
    pthread_mutex_lock(&rb->mutex);

    // Attendi finché buffer non pieno o shutdown
    while (rb->count == rb->capacity && !rb->shutdown) {
        pthread_cond_wait(&rb->cond_push, &rb->mutex);
    }

    // Se shutdown, non inserire e restituisci false
    if (rb->shutdown) {
        pthread_mutex_unlock(&rb->mutex);
        return false;
    }

    // Inserisci elemento in posizione tail
    rb->data[rb->tail] = value;
    rb->tail = (rb->tail + 1) % rb->capacity;
    rb->count++;

    // Segnala che il buffer non è più vuoto (possibili pop in attesa)
    pthread_cond_signal(&rb->cond_pop);
    pthread_mutex_unlock(&rb->mutex);
    return true;
}

// Estrae un elemento dal buffer.
// Restituisce true con valore in *value se successo.
// Restituisce false se buffer vuoto e shutdown, o se errore.
// Se il buffer è vuoto (ma non in shutdown), il thread attende.
bool ring_buffer_pop(ring_buffer_t* rb, int* value) {
    pthread_mutex_lock(&rb->mutex);

    // Attendi finché buffer non vuoto o shutdown
    while (rb->count == 0 && !rb->shutdown) {
        pthread_cond_wait(&rb->cond_pop, &rb->mutex);
    }

    // Se buffer vuoto e shutdown, nessun dato disponibile
    if (rb->count == 0 && rb->shutdown) {
        pthread_mutex_unlock(&rb->mutex);
        return false;
    }

    // Estrai elemento da posizione head
    *value = rb->data[rb->head];
    rb->head = (rb->head + 1) % rb->capacity;
    rb->count--;

    // Segnala che il buffer non è più pieno (possibili push in attesa)
    pthread_cond_signal(&rb->cond_push);
    pthread_mutex_unlock(&rb->mutex);
    return true;
}

// Attiva la modalità shutdown: tutti i thread in attesa su push/pop
// si risveglieranno e otterranno false/errore.
void ring_buffer_shutdown(ring_buffer_t* rb) {
    pthread_mutex_lock(&rb->mutex);
    rb->shutdown = true;
    // Risveglia tutti i thread in attesa (push e pop)
    pthread_cond_broadcast(&rb->cond_push);
    pthread_cond_broadcast(&rb->cond_pop);
    pthread_mutex_unlock(&rb->mutex);
}
